// Parse Gemini output — handle markdown code blocks
const raw = items[0].json.text || '';
const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { ideas: Array.isArray(parsed) ? parsed : [parsed], source: 'gemini' } }];
} catch(e) {
  // Try to extract JSON array from text
  const match = cleaned.match(/\[\s*{[\s\S]*}\s*\]/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    return [{ json: { ideas: parsed, source: 'gemini' } }];
  }
  return [{ json: { ideas: [], error: e.message, raw: cleaned.slice(0, 500), source: 'gemini' } }];
}

// Parse Ollama output
const raw = items[0].json.response || '';
const cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { ideas: Array.isArray(parsed) ? parsed : [parsed], source: 'ollama' } }];
} catch(e) {
  const match = cleaned.match(/\[\s*{[\s\S]*}\s*\]/);
  if (match) {
    return [{ json: { ideas: JSON.parse(match[0]), source: 'ollama' } }];
  }
  return [{ json: { ideas: [], error: 'Both Gemini and Ollama failed: ' + e.message, source: 'ollama' } }];
}
